use "C:\Users\86132\Desktop\hh.dta",clear
foreach var of varlist id year incomerate pt gdp caizhengzhichu cpi waimao population{
destring `var',replace
}
foreach var of varlist gdp caizhengzhichu cpi waimao population{
	gen l`var' = log(`var')
}
// 生成距离变量并进行修正
gen distance = year - pt
//单期did和多期did的区别就在这里。单期did是减去一个固定的数，多期是减去一个变量
replace distance=. if distance>500
replace distance = -4 if distance <= -4
tab distance, missing

replace pt = 0 if pt==2015
replace pt = 0 if pt==2016
//replace pt = 0 if pt==2017
replace pt = 0 if pt==2018
gen Treat = 0
replace Treat = 1 if pt != 0


//hhh
xtset id year
gen did = (pt>year)
rename lpopulation did1
rename did lpopulation1
eststo m:xtreg incomerate did gdp cpi trade population i.year, fe robust
local m
esttab `m', nogap  replace not b(%4.2f) s(N r2_a) //输出回归结果
// 生成距离的虚拟变量
forvalues i = 1/4 {
    gen d_`i' = 0
    replace d_`i' = 1 if Treat == 1 & distance == -`i'
}
//d_`i'初始值为0
//如果Treat == 1 & distance == -`i'，那么将d_`i'的值赋为1

forvalues i = 1/9 {
    gen d`i' = 0
    replace d`i' = 1 if Treat == 1 & distance == `i'
}
//如果Treat == 1 & distance == `i'，那么将d`i'的值赋为1
gen d0 = 0
replace d0 = 1 if Treat == 1 & distance == 0
// 设置面板数据
xtset id year

// 回归分析
xtreg incomerate d_3 d_2 d_1 d0 d1-d9  gdp  cpi trade population i.year, fe robust
local m
//注意这里理论上不该加did。
//如果非要加一个did，那需要
// 设置图形输出的字体
graph set window fontface "Times New Roman"
graph set window fontfacesans "宋体"

// 使用 coefplot 绘制图形
coefplot, keep(d_3 d_2 d_1 d0 d1 d2 d3 d4 d5 d6 d7 d8 d9) ///
    coeflabels(d_3 = "-3" d_2 = "-2" d_1 = "-1" d0 = "0" d1 = "1" d2 = "2" d3 = "3" d4 = "4" d5 = "5" d6 = "6" d7 = "7" d8 = "8" d9 = "9") ///
    yline(0, lcolor(edkblue*0.8)) ///
    ylabel(0(0.5)1.5, labsize(medsmall) format(%02.1f)) vertical ///
    addplot(line @b @at) ytitle("{stSans:系数}", size(medsmall) orientation(h)) ///
    xtitle("{stSans:平行趋势检验}", size(medsmall)) yline(0) ///
    levels(95) scheme(s2color) ciopts(recast(rcap) lpattern(dash))
